6	/// Supported configuration file formats.
7	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
8	pub enum ConfigFormat {
9	    Toml,
10	    Yaml,
11	    Json,
12	}
13	
14	impl ConfigFormat {
15	    /// Detect format from a file extension.
16	    pub fn from_extension(ext: &str) -> Option<Self> {
17	        match ext {
18	            "toml" => Some(Self::Toml),
19	            "yaml" | "yml" => Some(Self::Yaml),
20	            "json" => Some(Self::Json),
21	            _ => None,
22	        }
23	    }
24	}
25	
26	/// Parse a configuration string into a JSON Value.
27	pub fn parse(input: &str, format: ConfigFormat) -> Result<Value, ParseError> {
28	    match format {
29	        ConfigFormat::Toml => {
30	            let table: toml::Value = toml::from_str(input)?;
31	            let json_str = serde_json::to_string(&table)?;
32	            Ok(serde_json::from_str(&json_str)?)
33	        }
34	        ConfigFormat::Yaml => Ok(serde_yaml::from_str(input)?),
35	        ConfigFormat::Json => Ok(serde_json::from_str(input)?),
36	    }
37	}
