39	/// A minimal schema representation for validation.
40	#[derive(Debug, Clone)]
41	pub struct Schema {
42	    pub required_keys: Vec<String>,
43	}
44	
45	/// Validate a parsed config value against a schema.
46	pub fn validate(value: &Value, schema: &Schema) -> Vec<ValidationError> {
47	    let mut errors = Vec::new();
48	    if let Some(obj) = value.as_object() {
49	        for key in &schema.required_keys {
50	            if !obj.contains_key(key) {
51	                errors.push(ValidationError::MissingKey(key.clone()));
52	            }
53	        }
54	    } else {
55	        errors.push(ValidationError::ExpectedObject);
56	    }
57	    errors
58	}
